# solution.py
# PhotoCollab System
# This system is designed to allow multiple users to collaboratively create and enhance a single photo project.

class PhotoCollab:
    """
    Main class for the PhotoCollab system.
    Handles user sessions, project management, and real-time collaboration.
    """
    def __init__(self):
        self.projects = {}
        self.users = {}

    def create_project(self, project_id, user_id):
        """
        Create a new photo project.
        """
        if project_id not in self.projects:
            self.projects[project_id] = {'user_ids': [user_id], 'photo_data': None}
            print(f"Project {project_id} created by user {user_id}.")
        else:
            print(f"Project {project_id} already exists.")

    def add_user_to_project(self, project_id, user_id):
        """
        Add a user to an existing project.
        """
        if project_id in self.projects:
            if user_id not in self.projects[project_id]['user_ids']:
                self.projects[project_id]['user_ids'].append(user_id)
                print(f"User {user_id} added to project {project_id}.")
            else:
                print(f"User {user_id} is already part of project {project_id}.")
        else:
            print(f"Project {project_id} does not exist.")

    def edit_photo(self, project_id, user_id, photo_data):
        """
        Edit the photo in a project.
        """
        if project_id in self.projects:
            if user_id in self.projects[project_id]['user_ids']:
                self.projects[project_id]['photo_data'] = photo_data
                print(f"Photo in project {project_id} edited by user {user_id}.")
            else:
                print(f"User {user_id} is not part of project {project_id}.")
        else:
            print(f"Project {project_id} does not exist.")

    def get_photo(self, project_id):
        """
        Get the current photo data from a project.
        """
        if project_id in self.projects:
            return self.projects[project_id]['photo_data']
        else:
            print(f"Project {project_id} does not exist.")
            return None

# Example usage
if __name__ == "__main__":
    photo_collab = PhotoCollab()
    photo_collab.create_project("project1", "user1")
    photo_collab.add_user_to_project("project1", "user2")
    photo_collab.edit_photo("project1", "user1", "photo_data_here")
    print(photo_collab.get_photo("project1"))
```

